queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?functionname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFunction ?child ; p:hasTraffic_Camera ?parent . } GROUP BY ?child }
  ?child p:name ?functionname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Traffic_Camera } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?functionname WHERE {
  ?traffic_camera_function a :Traffic_Camera_Function .
  ?function a :Function .
  ?traffic_camera_function p:hasFunction ?function .
  ?traffic_camera a :Traffic_Camera .
  ?traffic_camera_function p:hasTraffic_Camera ?traffic_camera .
  ?traffic_camera p:name ?name .
  ?function p:name ?functionname .
} }
  collective: { SELECT ?functionname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFunction ?child ; p:hasTraffic_Camera ?parent . } GROUP BY ?child }
  ?child p:name ?functionname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Traffic_Camera } }
  FILTER(?nf = ?total)
} }
}
